\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Toggles visibility of envelopes in lanes for selected tracks. Preserves and restores automation mode when hiding or showing envelopes.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Aligns selected items sequentially to project markers starting from the edit cursor. Uses snap offset or item start as alignment reference.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Aligns selected items to a chosen project marker. Uses take marker, snap offset, or item start as alignment reference.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Alternates selected tracks left and right by a user-defined pan amount. Prompts for a value (0\u8211-100) and remembers the last used amount.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Alternates selected tracks between hard left and hard right pan positions.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Duplicates selected tracks while preserving FX, routing, and settings. Removes all items and automation envelopes and resets automation mode.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Moves overlapping selected items to new lane tracks per source track. Preserves track names and colors and minimizes lane creation.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Moves selected items to the selected destination track. Preserves exact item positions.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Splits selected unlocked items at the current loop start and loop end. Selects only the resulting pieces inside the loop range. Does nothing if there is no loop selection.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Appends sequential numbers to the end of selected track names.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Capitalizes parent track names and converts child track names to lowercase.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Capitalizes selected parent track names and converts selected child track names to lowercase.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Converts selected track names to uppercase.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Renames selected items based on their track name. Supports take name appending and smart numbering.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Renames selected tracks using a category name. Supports optional sequential numbering and persistent categories.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Renames selected tracks sequentially using a user-defined base name. Skips numbering when only one track is selected.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Toggles record arm on selected tracks. Enables monitoring only for instrument-related tracks and skips utility tracks.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Creates a sampler track with ReaSamplOmatic5000 from selected items. Sets up track, routing, and monitoring for immediate use.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Interactive tool for spacing items with progressive curves. Supports linear, exponential, and logarithmic spacing.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Creates progressively shorter duplicates of selected items. Supports directional control, spacing, and live preview.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Imports audio files from a folder to separate tracks at the "=START" marker. Sets tempo, updates reference region, and prepares the project automatically.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Imports video files with automatic frame rate detection and project FPS matching. Places videos using markers or sequentially and manages video tracks automatically.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Adrian Klein Scripts\par}
{\pard \ql \f0 \sa180 \li0 \fi0 A ReaPack repository for personal scripts used in daily work for sound design, editing, recording, project formatting, and workflow.\par}
{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel1 \b \fs32 Install in REAPER\par}
{\pard \ql \f0 \sa180 \li0 \fi0 In REAPER, go to:\par}
{\pard \ql \f0 \sa180 \li0 \fi0 Extensions \u8594 ? ReaPack \u8594 ? Import repositories\par}
{\pard \ql \f0 \sa180 \li0 \fi0 Then import this URL:\par}
{\pard \ql \f0 \sa180 \li0 \fi0 {\f1 https://raw.githubusercontent.com/kleinadrian/reaper-scripts-reapack/master/index.xml}\par}
{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel1 \b \fs32 Categories\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Automation\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Editing\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Organization\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Recording\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Sound Design\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Workflow\sa180\par}
{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel1 \b \fs32 Notes\par}
{\pard \ql \f0 \sa180 \li0 \fi0 These scripts are built from real-world use and will continue to evolve over time.\par}
}
